mapper.update:
BEGIN

    UPDATE T_BUS_CARGO_INFO
    SET SURPLUS_RIGHTS_QUANTITY = SURPLUS_RIGHTS_QUANTITY - #{cargoInfo.surplusRightsQuantity,jdbcType=DECIMAL},
    UPDATE_BY = #{cargoInfo.loginUserId,jdbcType=BIGINT},
    UPDATE_BY_NAME = #{cargoInfo.loginUserName,jdbcType=VARCHAR},
    UPDATE_TIME = #{cargoInfo.now,jdbcType=TIMESTAMP}
    WHERE ID = #{cargoInfo.id,jdbcType=BIGINT};

END;

