SELECT ID, PORT_STORAGE_ID, CARGO_INFO_ID, WORK_DATE, CLASS_CODE, CLASS_NAME, PROCESS_DETAIL_CODE, PROCESS_DETAIL_NAME, STOREHOUSE_ID, STOREHOUSE_NAME, REGION_ID, REGION_NAME, MASS_ID, MASS_NAME, QUANTITY, TON, INOUT_TYPE, INOUT_STORAGE_CODE, INOUT_STORAGE_NAME, WORK_TICKET_ID, WORK_TICKET_DETAIL_ID, CARGO_TALLY_ID, CARGO_TALLY_DETAIL_ID, INOUT_DATE, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, COMPANY_ID, COMPANY_NAME, CLEAN_MASS_SIGN, CLEAN_MASS_BY, CLEAN_MASS_BY_NAME, CLEAN_MASS_TIME, CARGO_TRANSFER_ID FROM T_PRD_PORT_STORAGE_DETAIL WHERE ( CARGO_MIX_RECORD_ID IN
#{cargoMixRecordId,jdbcType=BIGINT}
OR CARGO_MIX_DETAIL_ID IN
#{cargoMixRecordId,jdbcType=BIGINT}
)

mapper.update:
UPDATE T_BUS_CARGO_MIX_RECORD
SET CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT},
    STATUS        = #{status,jdbcType=VARCHAR}
WHERE ID = #{id,jdbcType=BIGINT}

mapper.select:
select TBCI.CARGO_INFO_NO "cargoInfoNo",tppsd.REGION_NAME "regionName",tppsd.MASS_NAME "massName",sum(tppsd.TON) "ton"
from T_PRD_PORT_STORAGE_DETAIL tppsd
         left join T_BUS_CARGO_INFO TBCI on tppsd.CARGO_INFO_ID = TBCI.ID
where tppsd.id is not null and tppsd.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT}
  and tppsd.MASS_ID = #{massId,jdbcType=BIGINT}
group by TBCI.CARGO_INFO_NO,tppsd.REGION_NAME,tppsd.MASS_NAME
